const TARGETS={
 good:{name:'The Good Padel Club',url:'https://www.thegoodpadelclub.com/',terms:['alam sutera','ciumbuleuit','court','padel']},
 jungle:{name:'Jungle Padel',url:'https://junglepadel.bookandgo.app/',terms:['pererenan','surabaya','court','padel']},
 lounge:{name:'Padel Lounge Tangerang',url:'https://kyzn.life/',terms:['padel lounge','tangerang','court','padel']}
};
function decode(value=''){return String(value).replace(/\\u([0-9a-f]{4})/gi,(_,x)=>String.fromCharCode(parseInt(x,16))).replace(/\\x([0-9a-f]{2})/gi,(_,x)=>String.fromCharCode(parseInt(x,16))).replace(/\\\//g,'/').replace(/&amp;/g,'&').replace(/&quot;/g,'"').replace(/&#39;/g,"'")}
function plain(value=''){return decode(value).replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim()}
async function get(url,timeout=8000){const controller=new AbortController(),timer=setTimeout(()=>controller.abort(),timeout);try{const response=await fetch(url,{redirect:'follow',signal:controller.signal,headers:{'user-agent':'Mozilla/5.0 (compatible; PadelSportIndonesia/1.0; +https://padelsport.vercel.app)','accept':'text/html,application/javascript,application/json,text/plain'}});return{ok:response.ok,status:response.status,url:response.url,text:await response.text(),type:response.headers.get('content-type')||''}}catch(error){return{ok:false,status:0,url,error:String(error.message||error),text:'',type:''}}finally{clearTimeout(timer)}}
function assetUrls(html,base){const out=[];for(const regex of [/<script[^>]+src=["']([^"']+)["']/gi,/<link[^>]+href=["']([^"']+)["'][^>]+(?:rel=["'](?:preload|modulepreload)["']|as=["']script["'])/gi])for(const match of html.matchAll(regex)){try{const url=new URL(match[1],base);if(/^https?:$/.test(url.protocol)&&/\.(?:js|json)(?:[?#]|$)|\/_next\/|\/assets\//i.test(url.href))out.push(url.href)}catch{}}return[...new Set(out)]}
function apiUrls(text,base){const out=[];for(const match of decode(text).matchAll(/(?:https?:\\?\/\\?\/[^"'\s)]+|["'](\/[^"']*(?:api|court|venue|location|facility|booking)[^"']*)["'])/gi)){const raw=match[1]||match[0];try{const url=new URL(raw.replace(/^['"]|['"]$/g,''),base);if(/^https?:$/.test(url.protocol)&&!url.pathname.match(/\.(?:png|jpg|jpeg|gif|svg|webp|woff2?|ttf|otf)$/i))out.push(url.href)}catch{}}return[...new Set(out)]}
function snippets(text,terms=[]){const clean=decode(text),rows=[];for(const term of terms){let from=0;const needle=term.toLowerCase();while(rows.length<80){const index=clean.toLowerCase().indexOf(needle,from);if(index<0)break;const snippet=plain(clean.slice(Math.max(0,index-220),Math.min(clean.length,index+needle.length+320)));if(snippet)rows.push({term,snippet});from=index+needle.length}}return [...new Map(rows.map(row=>[row.snippet,row])).values()]}
function courtCandidates(text=''){const clean=plain(text),rows=[];for(const pattern of [/(\d{1,2})\s+(?:premium\s+|indoor\s+|outdoor\s+|semi[- ]?indoor\s+|panoramic\s+)?padel\s+courts?/gi,/(?:has|have|with|home to|memiliki|punya|tersedia|terdapat|dengan)\s+(\d{1,2})\s+(?:buah\s+|unit\s+)?(?:padel\s+)?(?:court|courts|lapangan)/gi,/(\d{1,2})\s+(?:buah\s+|unit\s+)?(?:lapangan|court)\s+padel/gi,/(?:court|courts|lapangan)\s*[:=-]\s*(\d{1,2})/gi])for(const match of clean.matchAll(pattern)){const value=Number(match[1]);if(value>=1&&value<=30)rows.push({value,snippet:clean.slice(Math.max(0,match.index-180),Math.min(clean.length,match.index+match[0].length+220))})}return rows}
module.exports=async(req,res)=>{try{const key=String(req.query?.key||'').toLowerCase(),target=TARGETS[key];if(!target){res.status(400).json({error:'key must be one of: '+Object.keys(TARGETS).join(', ')});return}const root=await get(target.url),assets=assetUrls(root.text,root.url||target.url).slice(0,24),files=[{url:root.url||target.url,status:root.status,type:root.type,text:root.text}],apis=new Set();for(const url of assets){const file=await get(url,6500);files.push(file);for(const api of apiUrls(file.text,file.url||url))apis.add(api)}const apiFiles=[];for(const url of [...apis].filter(url=>{try{const host=new URL(url).hostname;return host===new URL(target.url).hostname||/(bookandgo|supabase|firebase|api)/i.test(host)}catch{return false}}).slice(0,12)){const file=await get(url,5500);if(file.ok&&file.text.length<3000000)apiFiles.push(file)}const all=[...files,...apiFiles],evidence=[];for(const file of all){for(const row of snippets(file.text,target.terms))evidence.push({...row,url:file.url});for(const row of courtCandidates(file.text))evidence.push({term:'court_candidate',...row,url:file.url})}const candidates=evidence.filter(row=>row.value).reduce((acc,row)=>{const found=acc.find(item=>item.value===row.value);if(found)found.items.push(row);else acc.push({value:row.value,items:[row]});return acc},[]).sort((a,b)=>new Set(b.items.map(i=>i.url)).size-new Set(a.items.map(i=>i.url)).size||b.items.length-a.items.length);res.setHeader('Cache-Control','no-store');res.status(200).json({key,name:target.name,root:{url:root.url,status:root.status,type:root.type},assetCount:assets.length,fetchedFiles:all.map(file=>({url:file.url,status:file.status,type:file.type,size:file.text?.length||0})),discoveredApiUrls:[...apis].slice(0,40),candidates:candidates.slice(0,12).map(item=>({value:item.value,sourceCount:new Set(item.items.map(i=>i.url)).size,items:item.items.slice(0,12)})),snippets:evidence.filter(row=>!row.value).slice(0,80)})}catch(error){console.error(error);res.status(500).json({error:String(error.stack||error)})}};
